    // 媒体信息日志(输出到左侧 mediaLogBox)
    function mediaLog(msg, type) {
        var colors = { 'info': '#8b949e', 'success': '#3fb950', 'error': '#f85149', 'warning': '#d29922' };
        var color = colors[type] || '#8b949e';
        var box = document.getElementById('mediaLogBox');
        if (!box) return;
        var entry = document.createElement('div');
        entry.style.cssText = 'color:' + color + ';font-size:11px;font-family:monospace;line-height:1.4;margin-bottom:2px';
        entry.textContent = msg;
        box.appendChild(entry);
        while (box.children.length > 100) box.removeChild(box.firstChild);
        box.scrollTop = box.scrollHeight;
    }

    // 媒体输入状态更新
    function updateMediaInputStatus(state) {
        var dot = document.getElementById('mediaInputDot');
        var status = document.getElementById('mediaInputStatus');
        if (!dot || !status) return;
        if (state === 'playing') {
            dot.className = 'status-dot green';
            status.textContent = '媒体输入: 已连接';
        } else if (state === 'connecting') {
            dot.className = 'status-dot yellow';
            status.textContent = '媒体输入: 连接中';
        } else {
            dot.className = 'status-dot red';
            status.textContent = '媒体输入: 等待连接';
        }
    }

    // 媒体输出状态更新
    function updateMediaOutputStatus(state) {
        var dot = document.getElementById('mediaOutputDot');
        var status = document.getElementById('mediaOutputStatus');
        if (!dot || !status) return;
        // Clear all inline styles first
        dot.style.background = '';
        dot.style.boxShadow = '';
        if (state === 'recording') {
            dot.className = 'status-dot green';
            status.textContent = '录制';
        } else if (state === 'streaming') {
            dot.className = 'status-dot blue';
            status.textContent = '推流';
        } else {
            dot.className = 'status-dot';
            dot.style.background = '#30363d';
            dot.style.boxShadow = 'none';
            status.textContent = '未录制';
        }
    }

