            if min_time > 0:
                min_val = f"1/{int(1/min_time)}"
            else:
                min_val = max_limit

            xml_str = re.sub(
                r'(<minShutterLevelLimit>)[^<]*(</minShutterLevelLimit>)',
                f'\\g<1>{min_val}\\g<2>',
                xml_str
            )

        put_resp = client.put("/Image/channels/1/Shutter", xml_str)
        if put_resp.status_code == 200:
            log_info("image", "slow_shutter", {"device": device_id, "ratio": ratio})
            return {"success": True, "message": f"慢快门: {'关闭' if ratio == 0 else f'{ratio}x'}"}
        else:
            return {"success": False, "message": f"设置失败: HTTP {put_resp.status_code}"}
    except Exception as e:
        return {"success": False, "message": f"设置慢快门异常: {e}"}


