function loadSlowShutter(deviceIp) {
    apiGet('/api/v1/ptz/' + deviceIp + '/image/slow-shutter').then(function(r) {
        var sel = document.getElementById('slowShutterSelect');
        if (!sel) return;
        if (!r || !r.success || !r.data) { sel.disabled = true; return; }
        var d = r.data;
        if (!d.supported) { sel.disabled = true; return; }
        sel.disabled = false;
        var ratios = [0, 1.25, 2, 4, 8];
        sel.innerHTML = '';
        ratios.forEach(function(ratio) {
            var opt = document.createElement('option');
            opt.value = ratio;
            opt.textContent = ratio === 0 ? '关闭' : ratio + 'x';
            if (Math.abs((d.ratio || 1) - ratio) < 0.01) opt.selected = true;
            sel.appendChild(opt);
        });
    });
}

function setSlowShutter(val) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    var ratio = parseFloat(val);
    apiPut('/api/v1/ptz/' + dev + '/image/slow-shutter', { ratio: ratio }).then(function(r) {
        if (r && r.success) {
            showToast('success', r.message);
            if (typeof operationLog === 'function') operationLog('慢快门: ' + r.message, 'success');
        }
    });

