async def get_slow_shutter(device_id: str) -> dict:
    """获取慢快门状态和倍率。"""
    import xml.etree.ElementTree as ET
    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZDeviceController未初始化"}

    target_ip = _resolve_device_id_to_ip(mgr, device_id)
    if not target_ip:
        return {"success": False, "message": f"无法解析设备标识: {device_id}"}

    ctrl, err = mgr._get_controller(target_ip)
    if err:
        return {"success": False, "message": err}

    client = ctrl.client
    try:
        resp = client.get("/Image/channels/1/Shutter")
        if resp.status_code != 200:
            return {"success": False, "message": f"获取慢快门失败: HTTP {resp.status_code}"}

        root = ET.fromstring(resp.xml)
        shutter_level = None
        min_limit = None
        max_limit = None

        for elem in root.iter():
            tag = elem.tag.split("}")[-1] if "}" in elem.tag else elem.tag
            if tag in ("ShutterLevel", "shutterLevel"):
                shutter_level = (elem.text or "").strip()
            elif tag in ("minShutterLevelLimit", "MinShutterLevelLimit"):
                min_limit = (elem.text or "").strip()
            elif tag in ("maxShutterLevelLimit", "MaxShutterLevelLimit"):
                max_limit = (elem.text or "").strip()

        supported = bool(min_limit and max_limit and min_limit != max_limit)

        ratio = 1.0
        if supported and shutter_level and min_limit:
            from src.controlpanel.region_base import _parse_shutter_level
            base_time = _parse_shutter_level(shutter_level)
            min_time = _parse_shutter_level(min_limit)
            if base_time > 0 and min_time > 0:
                ratio = round(base_time / min_time, 2)

        return {
            "success": True,
            "data": {
                "supported": supported,
                "enabled": ratio > 1.0,
                "ratio": ratio,
                "shutter_level": shutter_level,
                "min_limit": min_limit,
                "max_limit": max_limit
            }
        }
    except Exception as e:
        return {"success": False, "message": f"获取慢快门异常: {e}"}


@api_router.put("/ptz/{device_id}/image/slow-shutter", summary="设置慢快门", tags=["Image"])
async def set_slow_shutter(device_id: str, body: dict) -> dict:
    """设置慢快门倍率。

    请求体:
        {"ratio": 0}  → 关闭
        {"ratio": 1.25} → 1.25倍率
        {"ratio": 2} → 2倍率
        {"ratio": 4} → 4倍率
        {"ratio": 8} → 8倍率
    """
    import re
    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZDeviceController未初始化"}

    target_ip = _resolve_device_id_to_ip(mgr, device_id)
    if not target_ip:
        return {"success": False, "message": f"无法解析设备标识: {device_id}"}

    ctrl, err = mgr._get_controller(target_ip)
    if err:
        return {"success": False, "message": err}

    client = ctrl.client
    ratio = body.get("ratio", 0)

    try:
        resp = client.get("/Image/channels/1/Shutter")
        if resp.status_code != 200:
            return {"success": False, "message": f"获取当前快门失败: HTTP {resp.status_code}"}

        xml_str = resp.xml

        if ratio == 0:
            import xml.etree.ElementTree as ET
            root = ET.fromstring(xml_str)
            max_limit = None
            for elem in root.iter():
                tag = elem.tag.split("}")[-1] if "}" in elem.tag else elem.tag
                if tag in ("maxShutterLevelLimit", "MaxShutterLevelLimit"):
                    max_limit = (elem.text or "").strip()
                    break
            if max_limit:
                xml_str = re.sub(
                    r'(<minShutterLevelLimit>)[^<]*(</minShutterLevelLimit>)',
                    f'\\g<1>{max_limit}\\g<2>',
                    xml_str
                )
        else:
            import xml.etree.ElementTree as ET
            from src.controlpanel.region_base import _parse_shutter_level
            root = ET.fromstring(xml_str)
            shutter_level = None
            max_limit = None
            for elem in root.iter():
                tag = elem.tag.split("}")[-1] if "}" in elem.tag else elem.tag
                if tag in ("ShutterLevel", "shutterLevel"):
                    shutter_level = (elem.text or "").strip()
                elif tag in ("maxShutterLevelLimit", "MaxShutterLevelLimit"):
                    max_limit = (elem.text or "").strip()

            if not shutter_level or not max_limit:
                return {"success": False, "message": "无法读取快门基准值"}

            base_time = _parse_shutter_level(shutter_level)
            min_time = base_time / ratio
            if min_time > 0:
                min_val = f"1/{int(1/min_time)}"
            else:
                min_val = max_limit

            xml_str = re.sub(
                r'(<minShutterLevelLimit>)[^<]*(</minShutterLevelLimit>)',
                f'\\g<1>{min_val}\\g<2>',
                xml_str
            )

        put_resp = client.put("/Image/channels/1/Shutter", xml_str)
        if put_resp.status_code == 200:
            log_info("image", "slow_shutter", {"device": device_id, "ratio": ratio})
            return {"success": True, "message": f"慢快门: {'关闭' if ratio == 0 else f'{ratio}x'}"}
        else:
            return {"success": False, "message": f"设置失败: HTTP {put_resp.status_code}"}
    except Exception as e:
        return {"success": False, "message": f"设置慢快门异常: {e}"}


